export interface ISetTpslParams {
  coin: string;
  szDecimals: number;
  assetId: number;
  isMobile?: boolean;
  // Seed a single trigger field when opened from a chart position context.
  presetTriggerPrice?: string;
  presetTpsl?: 'tp' | 'sl';
}

interface ISetTpslFormProps extends Omit<ISetTpslParams, 'isMobile'> {
  onClose: () => void;
}

function MarkPrice({ coin }: { coin: string }) {
  const { midFormattedByDecimals } = usePerpsMidPrice({ coin });
  return (
    <SizableText size="$bodyMdMedium">{midFormattedByDecimals}</SizableText>
  );
}

function CancelOrderButton({
  disabled,
  label,
  onPress,
}: {
  disabled: boolean;
  label: string;
  onPress?: () => void;
}) {
  return (
    <XStack
      alignItems="center"
      justifyContent="center"
      h={24}
      minWidth={56}
      px="$2.5"
      ml="$2"
      borderRadius="$full"
      bg={disabled ? '$bgSubdued' : '$bgStrong'}
      borderWidth="$px"
      borderColor="$transparent"
      cursor={disabled ? 'default' : 'pointer'}
      hoverStyle={
        disabled ? undefined : { bg: '$bgHover', borderColor: '$borderHover' }
      }
      pressStyle={
        disabled
          ? undefined
          : { bg: '$bgActive', borderColor: '$borderActive', opacity: 0.88 }
      }
      onPress={disabled ? undefined : onPress}
      flexShrink={0}
    >
      <SizableText size="$bodySm" color={disabled ? '$textDisabled' : '$text'}>
        {label}
      </SizableText>
    </XStack>
  );
}

function ExistingTpslOrderSummary({
  relationLabel,
  triggerPx,
  pnlLabel,
  pnlValue,
  disabled,
  cancelLabel,
  onCancel,
}: {
  relationLabel: string;
  triggerPx: string;
  pnlLabel: string;
  pnlValue: string;
  disabled: boolean;
  cancelLabel: string;
  onCancel: () => void;
}) {
  const isNegative = pnlValue.startsWith('-');
  const formattedPnlValue = isNegative
    ? `-$${pnlValue.slice(1)}`
    : `$${pnlValue}`;

  return (
    <YStack gap="$1.5" py="$1">
      <XStack alignItems="center" justifyContent="space-between" gap="$3">
        <XStack alignItems="center" gap="$2" flex={1} minWidth={0}>
          <SizableText size="$bodyMd" color="$textSubdued" flexShrink={0}>
            {relationLabel}
          </SizableText>
          <SizableText size="$bodyLgMedium" numberOfLines={1} flexShrink={1}>
            {triggerPx}
          </SizableText>
        </XStack>
        <CancelOrderButton
          disabled={disabled}
          label={cancelLabel}
          onPress={onCancel}
        />
      </XStack>
      <XStack alignItems="center" justifyContent="flex-end" gap="$1.5">
        <SizableText size="$bodySm" color="$textSubdued">
          {pnlLabel}
        </SizableText>
        <SizableText
          size="$bodyMdMedium"
          color={isNegative ? '$red11' : '$green11'}
        >
          {formattedPnlValue}
        </SizableText>
      </XStack>
    </YStack>
  );
}

const SetTpslForm = memo(
  ({
    coin,
    szDecimals,
    assetId,
    presetTriggerPrice,
    presetTpsl,
    onClose = () => {},
  }: ISetTpslFormProps) => {
    const intl = useIntl();
    const hyperliquidActions = useHyperliquidActions();
    const { mid: midPrice } = usePerpsMidPrice({ coin });

    const activePositions = usePerpsAccountScopedActivePositions();
    const [activeAccount] = usePerpsActiveAccountAtom();
    const accountScopedAddress = usePerpsAccountScopedCacheAddress();
    const canSubmitForScopedAccount = isPerpsAccountAddressMatched({
      activeAccountAddress: activeAccount?.accountAddress,
      dataAccountAddress: accountScopedAddress,
    });
    const [{ accountAddress: openOrdersAccountAddress, openOrders }] =
      usePerpsActiveOpenOrdersAtom();
    const accountScopedOpenOrders = useMemo(
      () =>
        getPerpsAccountScopedListData({
          activeAccountAddress: accountScopedAddress,
          dataAccountAddress: openOrdersAccountAddress,
          data: openOrders,
        }),
      [accountScopedAddress, openOrders, openOrdersAccountAddress],
    );

    const currentPosition = useMemo(() => {
      return activePositions.find((p) => p.position.coin === coin)?.position;
    }, [activePositions, coin]);

    const currentTpslOrders = useMemo(() => {
      if (!currentPosition) return [];
      return accountScopedOpenOrders.filter(
        (o) =>
          o.coin === currentPosition.coin &&
          (o.orderType.startsWith('Take') || o.orderType.startsWith('Stop')),
      );
    }, [accountScopedOpenOrders, currentPosition]);

    useEffect(() => {
      if (!currentPosition || new BigNumber(currentPosition.szi || '0').eq(0)) {
        onClose();
      }
    }, [currentPosition, onClose]);

    const positionSize = useMemo(() => {
      if (!currentPosition) return new BigNumber(0);
      const size = new BigNumber(currentPosition.szi || '0').abs();
      return size;
    }, [currentPosition]);

    const isLongPosition = useMemo(() => {
      if (!currentPosition) return true;
      return new BigNumber(currentPosition.szi || '0').gte(0);
    }, [currentPosition]);

    // Position is full position when sz is 0.0
    const tpOrder = useMemo(() => {
      return (
        currentTpslOrders.filter(
          (order) => order.orderType.startsWith('Take') && order.sz === '0.0',
        )?.[0] || null
      );
    }, [currentTpslOrders]);
    const slOrder = useMemo(() => {
      return (
        currentTpslOrders.filter(
          (order) => order.orderType.startsWith('Stop') && order.sz === '0.0',
        )?.[0] || null
      );
    }, [currentTpslOrders]);

    const expectedProfit = useMemo(() => {
      if (tpOrder && currentPosition) {
        return calculateProfitLoss({
          entryPrice: currentPosition.entryPx,
          exitPrice: tpOrder.triggerPx,
          amount: positionSize,
          side: isLongPosition ? 'long' : 'short',
        });
      }
      return null;
    }, [tpOrder, positionSize, currentPosition, isLongPosition]);
    const expectedLoss = useMemo(() => {
      if (slOrder && currentPosition) {
        return calculateProfitLoss({
          entryPrice: currentPosition.entryPx,
          exitPrice: slOrder.triggerPx,
          amount: positionSize,
          side: isLongPosition ? 'long' : 'short',
        });
      }
      return null;
    }, [slOrder, positionSize, currentPosition, isLongPosition]);

    const handleCancelOrder = useCallback(
      async (order: IPerpsFrontendOrder) => {
        if (!canSubmitForScopedAccount) {
          return;
        }
        await hyperliquidActions.current.ensureTradingEnabled();
        const symbolMeta =
          await backgroundApiProxy.serviceHyperliquid.getSymbolMeta({
            coin: order.coin,
          });
        const tokenInfo = symbolMeta;
        if (!tokenInfo) {
          console.warn(`Token info not found for coin: ${order.coin}`);
          return;
        }
        await hyperliquidActions.current.cancelOrder({
          orders: [
            {
              assetId: tokenInfo.assetId,
              oid: order.oid,
            },
          ],
        });
      },
      [canSubmitForScopedAccount, hyperliquidActions],
    );

    const entryPrice = useMemo(() => {
      return currentPosition?.entryPx || '0';
    }, [currentPosition]);

    const leverage = useMemo(() => {
      if (!currentPosition) return 1;
      const positionValue = new BigNumber(
        currentPosition.positionValue || '0',
      ).abs();
      const marginUsed = new BigNumber(currentPosition.marginUsed || '0');
      if (marginUsed.gt(0) && positionValue.gt(0)) {
        return Math.round(positionValue.dividedBy(marginUsed).toNumber());
      }
      return 1; // Default leverage if calculation fails
    }, [currentPosition]);

    const [formData, setFormData] = useState(() => ({
      tpPrice:
        presetTriggerPrice && presetTpsl === 'tp' ? presetTriggerPrice : '',
      slPrice:
        presetTriggerPrice && presetTpsl === 'sl' ? presetTriggerPrice : '',
      amount: '',
      percentage: 100,
    }));

    const [configureAmount, setConfigureAmount] = useState(false);

    const [isSubmitting, setIsSubmitting] = useState(false);
    const displayName = useMemo(() => {
      if (!currentPosition) return '';
      const parsed = parseDexCoin(currentPosition.coin);
      return parsed.displayName || currentPosition.coin;
    }, [currentPosition]);

    const calculatedAmount = useMemo(() => {
      const percentage = Number.isNaN(formData.percentage)
        ? 0
        : formData.percentage;
      const amount = positionSize.multipliedBy(percentage).dividedBy(100);
      // Floor-truncate to szDecimals to match HL lot-size rule (no over-rounding).
      return formatHlSize(amount, szDecimals) || '0';
    }, [positionSize, formData.percentage, szDecimals]);

    const handleTpslChange = useCallback(
      (data: { tpPrice: string; slPrice: string }) => {
        setFormData((prev) => ({
          ...prev,
          tpPrice: data.tpPrice,
          slPrice: data.slPrice,
        }));
      },
      [],
    );

    const handlePercentageChange = useCallback(
      (percentage: number) => {
        const amount = positionSize.multipliedBy(percentage).dividedBy(100);
        setFormData((prev) => ({
          ...prev,
          percentage,
          amount: formatHlSize(amount, szDecimals) || '0',
        }));
      },
      [positionSize, szDecimals],
    );

    const handleAmountChange = useCallback(
      (value: string) => {
        const processedValue = value.replace(/。/g, '.');
        if (processedValue === '') {
          setFormData((prev) => ({
            ...prev,
            amount: '',
            percentage: 0,
          }));
          return;
        }
        if (processedValue === '.') {
          setFormData((prev) => ({
            ...prev,
            amount: processedValue,
            percentage: 0,
          }));
          return;
        }

        let numericValue = new BigNumber(processedValue);
        if (numericValue.isNaN()) {
          return;
        }
        if (numericValue.gt(positionSize)) {
          numericValue = positionSize;
        }
        const percentage = positionSize.gt(0)
          ? numericValue.dividedBy(positionSize).multipliedBy(100).toNumber()
          : 0;

        setFormData((prev) => ({
          ...prev,
          amount: numericValue.toFixed(),
          percentage: Math.min(100, Math.max(0, percentage)),
        }));
      },
      [positionSize],
    );

    const isValidForm = useMemo(() => {
      const hasNewTpPrice = !tpOrder && formData.tpPrice.trim() !== '';
      const hasNewSlPrice = !slOrder && formData.slPrice.trim() !== '';
      return hasNewTpPrice || hasNewSlPrice;
    }, [formData.tpPrice, formData.slPrice, tpOrder, slOrder]);

    const handleSubmit = useCallback(async () => {
      try {
        if (!canSubmitForScopedAccount) {
          return;
        }
        setIsSubmitting(true);

        const tpslAmount = configureAmount
          ? formData.amount || calculatedAmount
          : '0';
        const tpslAmountBN = new BigNumber(tpslAmount);

        if (configureAmount) {
          if (!tpOrder && !slOrder && (!tpslAmount || tpslAmountBN.lte(0))) {
            Toast.error({
              title: intl.formatMessage({
                id: ETranslations.perp_tp_sl_error_enter,
              }),
            });
            return;
          }

          if (tpslAmountBN.gt(positionSize)) {
            Toast.error({
              title: intl.formatMessage({
                id: ETranslations.perp_tp_sl_error_amount,
              }),
            });
            return;
          }
        }

        if (!isValidForm) {
          Toast.error({
            title: intl.formatMessage({
              id: ETranslations.perp_tp_sl_error_price,
            }),
          });
          return;
        }

        const currentPriceBN = new BigNumber(midPrice || '0');
        const tpPriceBN = new BigNumber(formData.tpPrice || '0');
        const slPriceBN = new BigNumber(formData.slPrice || '0');

        if (
          !tpOrder &&
          formData.tpPrice &&
          tpPriceBN.isFinite() &&
          currentPriceBN.gt(0)
        ) {
          const isInvalid = isLongPosition
            ? tpPriceBN.lte(currentPriceBN)
            : tpPriceBN.gte(currentPriceBN);

          if (isInvalid) {
            let errorMessage = '';
            if (isLongPosition) {
              // Long + above
              errorMessage = intl.formatMessage({
                // invalid => invalid

                // oxlint-disable-next-line @cspell/spellchecker
                id: ETranslations.perp_invaild_tp_desc_1,
              });
            } else {
              // Short + below
              errorMessage = intl.formatMessage({
                // invalid => invalid

                // oxlint-disable-next-line @cspell/spellchecker
                id: ETranslations.perp_invaild_tp_desc_2,
              });
            }

            Toast.error({
              title: errorMessage,
            });
            return;
          }
        }

        if (
          !slOrder &&
          formData.slPrice &&
          slPriceBN.isFinite() &&
          currentPriceBN.gt(0)
        ) {
          const isInvalid = isLongPosition
            ? slPriceBN.gte(currentPriceBN)
            : slPriceBN.lte(currentPriceBN);
          if (isInvalid) {
            let errorMessage = '';
            if (isLongPosition) {
              // Long + below
              errorMessage = intl.formatMessage({
                // invalid => invalid

                // oxlint-disable-next-line @cspell/spellchecker
                id: ETranslations.perp_invaild_sl_desc_1,
              });
            } else {
              // Short + above
              errorMessage = intl.formatMessage({
                // invalid => invalid

                // oxlint-disable-next-line @cspell/spellchecker
                id: ETranslations.perp_invaild_sl_desc_2,
              });
            }

            Toast.error({
              title: errorMessage,
            });
            return;
          }
        }
        onClose();
        // Call the actual setPositionTpsl action
        await hyperliquidActions.current.setPositionTpsl({
          assetId,
          positionSize: tpslAmount,
          isBuy: isLongPosition,
          tpTriggerPx: !tpOrder ? formData.tpPrice || undefined : undefined,
          slTriggerPx: !slOrder ? formData.slPrice || undefined : undefined,
        });
      } catch (error) {
        // Error toast is handled in the action
        console.error('SetTpslModal handleSubmit error:', error);
        throw error;
      } finally {
        setIsSubmitting(false);
      }
    }, [
      configureAmount,
      formData.amount,
      calculatedAmount,
      formData.tpPrice,
      formData.slPrice,
      positionSize,
      assetId,
      isLongPosition,
      hyperliquidActions,
      onClose,
      slOrder,
      tpOrder,
      midPrice,
      isValidForm,
      intl,
      canSubmitForScopedAccount,
    ]);

    // Early return if position doesn't exist to prevent accessing undefined properties
    if (!currentPosition) {
      return null;
    }

    return (
      <YStack flex={1}>
        <YStack flex={1} gap="$3" pb="$6">
          <YStack gap="$3">
            <XStack justifyContent="space-between" alignItems="center">
              <SizableText size="$bodyMd" color="$textSubdued">
                {intl.formatMessage({
                  id: ETranslations.perp_token_selector_asset,
                })}
              </SizableText>
              <SizableText size="$bodyMdMedium">{displayName}</SizableText>
            </XStack>

            <XStack justifyContent="space-between" alignItems="center">
              <SizableText size="$bodyMd" color="$textSubdued">
                {intl.formatMessage({
                  id: ETranslations.perp_position_position_size,
                })}
              </SizableText>
              <SizableText size="$bodyMdMedium">
                {positionSize.toFixed(szDecimals)} {displayName}
              </SizableText>
            </XStack>

            <XStack justifyContent="space-between" alignItems="center">
              <SizableText size="$bodyMd" color="$textSubdued">
                {intl.formatMessage({
                  id: ETranslations.perp_position_entry_price,
                })}
              </SizableText>
              <SizableText size="$bodyMdMedium">{entryPrice}</SizableText>
            </XStack>

            <XStack justifyContent="space-between" alignItems="center">
              <SizableText size="$bodyMd" color="$textSubdued">
                {intl.formatMessage({
                  id: ETranslations.perp_position_mark_price,
                })}
              </SizableText>
              <MarkPrice coin={currentPosition.coin} />
            </XStack>
          </YStack>
          <Divider />
          {!tpOrder ? null : (
            <YStack gap="$1">
              {expectedProfit ? (
                <ExistingTpslOrderSummary
                  relationLabel={intl.formatMessage({
                    id: ETranslations.perp_tp_sl_above,
                  })}
                  triggerPx={tpOrder.triggerPx}
                  pnlLabel={intl.formatMessage({
                    id: ETranslations.perp_tp_sl_profit,
                  })}
                  pnlValue={expectedProfit}
                  disabled={!canSubmitForScopedAccount}
                  cancelLabel={intl.formatMessage({
                    id: ETranslations.perp_open_orders_cancel,
                  })}
                  onCancel={() => handleCancelOrder(tpOrder)}
                />
              ) : null}
            </YStack>
          )}
          <TpslInput
            price={entryPrice}
            side={isLongPosition ? 'long' : 'short'}
            szDecimals={szDecimals}
            leverage={leverage}
            tpsl={{ tpPrice: formData.tpPrice, slPrice: formData.slPrice }}
            onChange={handleTpslChange}
            amount={
              configureAmount
                ? formData.amount || calculatedAmount
                : positionSize.toFixed(szDecimals)
            }
            ifOnDialog
            hiddenTp={!!tpOrder}
            hiddenSl={!!slOrder}
          />
          {!slOrder ? null : (
            <YStack gap="$1">
              {expectedLoss ? (
                <ExistingTpslOrderSummary
                  relationLabel={intl.formatMessage({
                    id: ETranslations.perp_tp_sl_below,
                  })}
                  triggerPx={slOrder.triggerPx}
                  pnlLabel={intl.formatMessage({
                    id: ETranslations.perp_tp_sl_loss,
                  })}
                  pnlValue={expectedLoss}
                  disabled={!canSubmitForScopedAccount}
                  cancelLabel={intl.formatMessage({
                    id: ETranslations.perp_open_orders_cancel,
                  })}
                  onCancel={() => handleCancelOrder(slOrder)}
                />
              ) : null}
            </YStack>
          )}

          <YStack alignItems="flex-start" gap="$2" width="100%">
            <Checkbox
              testID="perp-checkbox"
              value={configureAmount}
              onChange={(checked) => setConfigureAmount(Boolean(checked))}
              label={intl.formatMessage({
                id: ETranslations.perp_tp_sl_partial_position,
              })}
              labelProps={{
                fontSize: getFontSize('$bodyMd'),
                color: '$textSubdued',
              }}
              containerProps={{ alignItems: 'center' }}
              width="$4"
              height="$4"
            />

            {configureAmount ? (
              <YStack width="100%" gap="$5">
                <YStack width="100%">
                  <TradingFormInput
                    label={intl.formatMessage({
                      id: ETranslations.dexmarket_details_history_amount,
                    })}
                    value={
                      formData.amount ||
                      (formData.percentage > 0 ? calculatedAmount : '')
                    }
                    onChange={handleAmountChange}
                    suffix={displayName}
                    validator={(value: string) => {
                      const processedValue = value.replace(/。/g, '.');
                      return validateSizeInput(processedValue, szDecimals);
                    }}
                    ifOnDialog
                  />
                </YStack>

                <YStack flex={1} width="100%">
                  <PerpsSlider
                    value={formData.percentage}
                    onChange={handlePercentageChange}
                    max={100}
                    min={0}
                    segments={4}
                    snapTapToSegment
                    sliderHeight={4}
                    showBubble={false}
                  />
                </YStack>
              </YStack>
            ) : null}
          </YStack>
        </YStack>
        <TradingGuardWrapper buttonSize={PERP_DIALOG_BUTTON_SIZE}>
          <Button
            testID="perp-processed-value-btn"
            size={PERP_DIALOG_BUTTON_SIZE}
            variant="primary"
            onPress={handleSubmit}
            disabled={
              !canSubmitForScopedAccount || !isValidForm || isSubmitting
            }
            loading={isSubmitting}
          >
            {intl.formatMessage({
              id: ETranslations.perp_confirm_order,
            })}
          </Button>{' '}
        </TradingGuardWrapper>
      </YStack>
    );
  },
);

SetTpslForm.displayName = 'SetTpslForm';

function SetTpslModal() {
  const intl = useIntl();
  const route =
    useRoute<RouteProp<IModalPerpParamList, EModalPerpRoutes.MobileSetTpsl>>();

  const { coin, szDecimals, assetId } = route.params;
  const navigation = useNavigation();
  const handleClose = useCallback(() => {
    navigation.goBack();
  }, [navigation]);
  return (
    <Page>
      <Page.Header
        title={intl.formatMessage({
          id: ETranslations.perp_tp_sl_position,
        })}
      />
      <Page.Body>
        <PerpsAccountSelectorProviderMirror>
          <PerpsProviderMirror>
            <YStack px="$4" flex={1}>
              <SetTpslForm
                coin={coin}
                szDecimals={szDecimals}
                assetId={assetId}
                onClose={handleClose}
              />
            </YStack>
          </PerpsProviderMirror>
        </PerpsAccountSelectorProviderMirror>
      </Page.Body>
    </Page>
  );
}

export default SetTpslModal;
export function showSetTpslDialog({
  coin,
  szDecimals,
  assetId,
  presetTriggerPrice,
  presetTpsl,
  intl,
}: ISetTpslParams & { intl: IntlShape }) {
  const dialogInstance = Dialog.show({
    title: intl.formatMessage({
      id: ETranslations.perp_tp_sl_position,
    }),
    description: intl.formatMessage({
      id: ETranslations.perp_tp_sl_position_desc,
    }),
    renderContent: (
      <PerpsAccountSelectorProviderMirror>
        <PerpsProviderMirror>
          <SetTpslForm
            coin={coin}
            szDecimals={szDecimals}
            assetId={assetId}
            presetTriggerPrice={presetTriggerPrice}
            presetTpsl={presetTpsl}
            onClose={() => {
              void dialogInstance.close();
            }}
          />
        </PerpsProviderMirror>
      </PerpsAccountSelectorProviderMirror>
    ),
    contentContainerProps: PERP_MOBILE_DIALOG_CONTENT_CONTAINER_PROPS,
    showFooter: false,
    onClose: () => {
      void dialogInstance.close();
    },
  });

  return dialogInstance;
}
